module shift_register(
	input clk,
	input reset,
	input load,
	input [11:0] data,
	output reg [11:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset)
        q <= 12'b000000000000;
    else if (load)
        q <= data;
    else
        q <= {1'b0, q[11:1]};
end
endmodule
